""" REST API Serializers for authentication and user accounts. """
from rest_framework import serializers from accounts.models import User
class UserSerializer(serializers.ModelSerializer): """Serializer for User model."""
class Meta: model = User fields = ('id', 'email', 'username', 'name', 'role', 'is_active', 'created_at', 'updated_at') read_only_fields = ('id', 'created_at', 'updated_at')
class UserDetailSerializer(UserSerializer): """Detailed serializer for User model with additional fields."""
class Meta(UserSerializer.Meta): fields = UserSerializer.Meta.fields + ('failed_login_attempts', 'locked_until', 'is_account_locked') read_only_fields = UserSerializer.Meta.read_only_fields + ('failed_login_attempts', 'locked_until')
class RegisterSerializer(serializers.ModelSerializer): """Serializer for user registration.""" password = serializers.CharField(write_only=True, min_length=6) password2 = serializers.CharField(write_only=True, min_length=6)
class Meta: model = User fields = ('email', 'username', 'name', 'password', 'password2')
def validate(self, data): if data['password'] != data['password2']: raise serializers.ValidationError("Passwords do not match.") return data
def create(self, validated_data): validated_data.pop('password2') user = User.objects.create_user(**validated_data) return user
class LoginSerializer(serializers.Serializer): """Serializer for user login.""" email = serializers.EmailField() password = serializers.CharField(write_only=True)
class Meta: fields = ('email', 'password')

""" REST API Serializers for disputes and resolutions. """
from rest_framework import serializers from disputes.models import Dispute, DisputeResolution, DisputeMessage, DisputeActivityLog
class DisputeMessageSerializer(serializers.ModelSerializer): """Serializer for dispute messages.""" sender_email = serializers.CharField(source='sender.email', read_only=True)
class Meta: model = DisputeMessage fields = ('id', 'sender_email', 'message', 'is_admin_message', 'created_at') read_only_fields = ('id', 'sender_email', 'created_at')
class DisputeActivityLogSerializer(serializers.ModelSerializer): """Serializer for dispute activity logs.""" actor_email = serializers.CharField(source='actor.email', read_only=True, allow_null=True)
class Meta: model = DisputeActivityLog fields = ('id', 'actor_email', 'action', 'timestamp') read_only_fields = ('id', 'actor_email', 'timestamp')
class DisputeResolutionSerializer(serializers.ModelSerializer): """Serializer for dispute resolutions.""" admin_email = serializers.CharField(source='resolved_by_admin.email', read_only=True, allow_null=True)
class Meta: model = DisputeResolution fields = ( 'id', 'resolution_type', 'buyer_refund_amount', 'seller_refund_amount', 'resolution_notes', 'admin_email', 'resolved_at' ) read_only_fields = ('id', 'admin_email', 'resolved_at')
class DisputeSerializer(serializers.ModelSerializer): """Serializer for Dispute model.""" buyer_email = serializers.CharField(source='buyer.email', read_only=True) seller_email = serializers.CharField(source='seller.email', read_only=True) raised_by_email = serializers.CharField(source='raised_by.email', read_only=True, allow_null=True) from_currency_code = serializers.CharField(source='from_currency.code', read_only=True) to_currency_code = serializers.CharField(source='to_currency.code', read_only=True) messages = DisputeMessageSerializer(many=True, read_only=True) activity_logs = DisputeActivityLogSerializer(many=True, read_only=True) resolution = DisputeResolutionSerializer(read_only=True)
class Meta: model = Dispute fields = ( 'id', 'transaction', 'buyer_email', 'seller_email', 'raised_by_email', 'from_currency_code', 'to_currency_code', 'foreign_amount', 'myr_amount', 'reason', 'status', 'evidence', 'seller_confirmation_status', 'messages', 'activity_logs', 'resolution', 'created_at', 'resolved_at' ) read_only_fields = ( 'id', 'transaction', 'buyer_email', 'seller_email', 'raised_by_email', 'messages', 'activity_logs', 'resolution', 'created_at', 'resolved_at' )

""" REST API Serializers for marketplace deals and transactions. """
from rest_framework import serializers from marketplace.models import Deal, Transaction
class DealSerializer(serializers.ModelSerializer): """Serializer for Deal model.""" seller_email = serializers.CharField(source='seller.email', read_only=True) from_currency_code = serializers.CharField(source='from_currency.code', read_only=True) to_currency_code = serializers.CharField(source='to_currency.code', read_only=True) receive_amount = serializers.SerializerMethodField() is_expired = serializers.SerializerMethodField()
class Meta: model = Deal fields = ( 'id', 'seller_email', 'from_currency_code', 'to_currency_code', 'amount', 'rate', 'trend', 'status', 'receive_amount', 'is_expired', 'created_at', 'expires_at', 'accepted_at' ) read_only_fields = ('id', 'seller_email', 'created_at', 'expires_at', 'accepted_at')
def get_receive_amount(self, obj): """Calculate receive amount for buyer.""" return float(obj.get_receive_amount())
def get_is_expired(self, obj): """Check if deal has expired.""" return obj.is_expired()
class TransactionSerializer(serializers.ModelSerializer): """Serializer for Transaction model.""" buyer_email = serializers.CharField(source='buyer.email', read_only=True, allow_null=True) seller_email = serializers.CharField(source='seller.email', read_only=True, allow_null=True) user_email = serializers.CharField(source='user.email', read_only=True, allow_null=True) from_currency_code = serializers.CharField(source='from_currency.code', read_only=True) to_currency_code = serializers.CharField(source='to_currency.code', read_only=True) deal_id = serializers.IntegerField(source='deal.id', read_only=True, allow_null=True)
class Meta: model = Transaction fields = ( 'id', 'type', 'status', 'buyer_email', 'seller_email', 'user_email', 'from_currency_code', 'to_currency_code', 'amount', 'received_amount', 'rate', 'payment_reference', 'deal_id', 'created_at', 'completed_at' ) read_only_fields = ( 'id', 'buyer_email', 'seller_email', 'user_email', 'created_at', 'completed_at' )

""" REST API Serializers for notifications. """
from rest_framework import serializers from notifications.models import Notification
class NotificationSerializer(serializers.ModelSerializer): """Serializer for Notification model.""" user_email = serializers.CharField(source='user.email', read_only=True)
class Meta: model = Notification fields = ( 'id', 'user_email', 'notification_type', 'message', 'related_id', 'is_read', 'created_at' ) read_only_fields = ('id', 'user_email', 'created_at')

""" REST API Serializers for wallets and balances. """
from rest_framework import serializers from wallets.models import Wallet, WalletBalance
class WalletBalanceSerializer(serializers.ModelSerializer): """Serializer for individual wallet balances.""" currency_code = serializers.CharField(source='currency.code', read_only=True) currency_name = serializers.CharField(source='currency.name', read_only=True) currency_symbol = serializers.CharField(source='currency.symbol', read_only=True)
class Meta: model = WalletBalance fields = ('id', 'currency_code', 'currency_name', 'currency_symbol', 'amount', 'last_updated') read_only_fields = ('id', 'last_updated')
class WalletSerializer(serializers.ModelSerializer): """Serializer for Wallet model with nested balances.""" balances = WalletBalanceSerializer(many=True, read_only=True) user_email = serializers.CharField(source='user.email', read_only=True) total_balance_usd = serializers.SerializerMethodField()
class Meta: model = Wallet fields = ('id', 'user_email', 'balance_total', 'total_balance_usd', 'balances', 'created_at', 'updated_at') read_only_fields = ('id', 'user_email', 'created_at', 'updated_at')
def get_total_balance_usd(self, obj): """Calculate approximate USD equivalent of total balance.""" # Simplified calculation - in production use ExchangeRate model return obj.get_total_balance() * 0.217 # Approximate MYR to USD conversion
